func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a random state parameter for CSRF protection
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Store the state in a cookie for validation when the user returns
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https",
		SameSite: http.SameSiteLaxMode,
		MaxAge:   600, // 10 minutes
	}
	http.SetCookie(w, stateCookie)

	// If a custom redirect path is provided, store it in a cookie
	// so we can redirect the user there after successful authentication
	if redirectPath != "" {
		redirectCookie := &http.Cookie{
			Name:     "oauth_redirect",
			Value:    redirectPath,
			Path:     "/",
			HttpOnly: true,
			Secure:   r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https",
			SameSite: http.SameSiteLaxMode,
			MaxAge:   600, // 10 minutes
		}
		http.SetCookie(w, redirectCookie)
	}

	// Use the session cookie if provided (for additional session tracking)
	if session != nil {
		session.Path = "/"
		session.HttpOnly = true
		session.Secure = r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https"
		session.SameSite = http.SameSiteLaxMode
		http.SetCookie(w, session)
	}

	// Generate the authorization URL with PKCE (Proof Key for Code Exchange)
	// for enhanced security
	codeVerifier := oauth2.GenerateVerifier()

	// Store the code verifier in a cookie
	verifierCookie := &http.Cookie{
		Name:     "oauth_verifier",
		Value:    codeVerifier,
		Path:     "/",
		HttpOnly: true,
		Secure:   r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https",
		SameSite: http.SameSiteLaxMode,
		MaxAge:   600, // 10 minutes
	}
	http.SetCookie(w, verifierCookie)

	// Build the authorization URL with PKCE and state
	authURL := OAuthConfig.AuthCodeURL(
		state,
		oauth2.AccessTypeOnline,
		oauth2.S256ChallengeOption(codeVerifier),
	)

	return authURL, nil
}

func main() {
	// Example HTTP handler demonstrating usage
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		redirectPath := r.URL.Query().Get("redirect")

		// Create a session cookie for tracking
		sessionCookie := &http.Cookie{
			Name:  "session_id",
			Value: "example-session-value",
		}

		authURL, err := GenerateAuthURL(redirectPath, sessionCookie, w, r)
		if err != nil {
			http.Error(w, fmt.Sprintf("Failed to generate auth URL: %v", err), http.StatusInternalServerError)
			return
		}

		// Redirect user to the OAuth provider
		http.Redirect(w, r, authURL, http.StatusFound)
	})

	http.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
		// Handle the OAuth callback - verify state and exchange code for token
		stateCookie, err := r.Cookie("oauth_state")
		if err != nil {
			http.Error(w, "State cookie not found", http.StatusBadRequest)
			return
		}

		stateParam := r.URL.Query().Get("state")
		if stateCookie.Value != stateParam {
			http.Error(w, "Invalid state parameter", http.StatusBadRequest)
			return
		}

		code := r.URL.Query().Get("code")
		if code == "" {
			http.Error(w, "Authorization code not found", http.StatusBadRequest)
			return
		}

		// Retrieve the code verifier from cookie
		verifierCookie, err := r.Cookie("oauth_verifier")
		if err != nil {
			http.Error(w, "Verifier cookie not found", http.StatusBadRequest)
			return
		}

		// Exchange the authorization code for an access token
		ctx := r.Context()
		token, err := OAuthConfig.Exchange(ctx, code, oauth2.VerifierOption(verifierCookie.Value))
		if err != nil {
			http.Error(w, fmt.Sprintf("Failed to exchange token: %v", err), http.StatusInternalServerError)
			return
		}

		// Clear the OAuth cookies
		http.SetCookie(w, &http.Cookie{Name: "oauth_state", Value: "", Path: "/", MaxAge: -1})
		http.SetCookie(w, &http.Cookie{Name: "oauth_verifier", Value: "", Path: "/", MaxAge: -1})

		// Check for custom redirect path
		redirectCookie, err := r.Cookie("oauth_redirect")
		finalRedirect := "/"
		if err == nil && redirectCookie.Value != "" {
			finalRedirect = redirectCookie.Value
			http.SetCookie(w, &http.Cookie{Name: "oauth_redirect", Value: "", Path: "/", MaxAge: -1})
		}

		// Token acquired successfully, redirect to final destination
		w.Header().Set("Content-Type", "text/plain")
		fmt.Fprintf(w, "Authentication successful! Token type: %s\nRedirecting to: %s\n", token.TokenType, finalRedirect)
	})

	fmt.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}

