func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state parameter
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Validate and sanitize the redirectPath to prevent open redirect vulnerabilities
	if redirectPath != "" {
		parsedURL, err := url.Parse(redirectPath)
		if err != nil {
			return "", fmt.Errorf("invalid redirect path: %w", err)
		}

		// Ensure the redirect path is relative or has the same host as the configured redirect URL
		configBaseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return "", fmt.Errorf("invalid config redirect URL: %w", err)
		}

		// Reject absolute URLs with different hosts (open redirect protection)
		if parsedURL.IsAbs() && parsedURL.Host != configBaseURL.Host {
			return "", fmt.Errorf("redirect path must use the same host as the configured callback")
		}

		// Prevent javascript: and data: schemes
		if parsedURL.Scheme != "" && parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			return "", fmt.Errorf("invalid scheme in redirect path")
		}
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	if redirectPath != "" {
		// If redirectPath is relative, resolve it against the base redirect URL
		configBaseURL, _ := url.Parse(OAuthConfig.RedirectURL)
		parsedRedirectPath, _ := url.Parse(redirectPath)
		config.RedirectURL = configBaseURL.ResolveReference(parsedRedirectPath).String()
