func splitPath(path string) []string {
	var parts []string
	current := ""
	for _, c := range path {
		if c == '/' {
			if current != "" {
				parts = append(parts, current)
				current = ""
			}
		} else {
			current += string(c)
		}
	}
	if current != "" {
		parts = append(parts, current)
	}
	return parts
}

// replaceDoubleDot is a helper for path normalization
func replaceDoubleDot(path string) string {
	result := ""
	i := 0
	for i < len(path)-1 {
