	callbackURL := baseRedirectURL.String()
	if redirectPath != "" {
		q := baseRedirectURL.Query()
		q.Set("redirect", redirectPath)
		baseRedirectURL.RawQuery = q.Encode()
		callbackURL = baseRedirectURL.String()
	}

