		return fmt.Errorf("path must be a valid relative path starting with /")
	}

	return nil
}

// isValidRelativePath checks if the path is a valid relative path
func isValidRelativePath(path string) bool {
	if path == "" {
		return true
	}
	if path[0] != '/' {
		return false
	}
	// Prevent directory traversal
	cleaned := url.PathEscape(path)
	unescaped, err := url.PathUnescape(cleaned)
	if err != nil {
